import json
from typing import Any

# Registered tool schemas (simplified)
TOOL_REGISTRY: dict[str, dict] = {
    "read_file": {
        "parameters": {
            "path": {"type": "string"},
        },
        "required": ["path"],
    },
    "post_notification": {
        "parameters": {
            "channel": {"type": "string"},
            "message": {"type": "string"},
        },
        "required": ["channel", "message"],
    },
}

class HallucinationDetector:
    def validate_tool_call(self, name: str, arguments: dict[str, Any]) -> None:
        # Type 1 — non-existent tool
        if name not in TOOL_REGISTRY:
            registered = list(TOOL_REGISTRY.keys())
            raise ValueError(
                f"Unknown tool '{name}'. Registered tools: {registered}"
            )

        schema = TOOL_REGISTRY[name]

        # Type 2 — missing required params
        for req in schema.get("required", []):
            if req not in arguments:
                raise ValueError(
                    f"Tool '{name}' missing required parameter '{req}'"
                )

        # Type 2 — wrong parameter types
        for param, value in arguments.items():
            if param not in schema["parameters"]:
                raise ValueError(
                    f"Tool '{name}' received unexpected parameter '{param}'"
                )
            expected_type = schema["parameters"][param]["type"]
            actual_type = type(value).__name__
            python_type_map = {"string": str, "integer": int, "boolean": bool}
            if expected_type in python_type_map:
                if not isinstance(value, python_type_map[expected_type]):
                    raise ValueError(
                        f"Parameter '{param}' must be {expected_type}, got {actual_type}"
                    )

detector = HallucinationDetector()

# Valid call — passes
detector.validate_tool_call("post_notification", {
    "channel": "#alerts",
    "message": "Build complete",
})

# Type 1 hallucination — caught
try:
    detector.validate_tool_call("send_slack_message", {"channel": "#dev", "message": "hi"})
except ValueError as e:
    print(f"BLOCKED: {e}")
# BLOCKED: Unknown tool 'send_slack_message'. Registered tools: ['read_file', 'post_notification']

from dataclasses import dataclass
from typing import Callable

@dataclass
class ToolResult:
    tool_name: str
    call_id: str
    content: str
    error: str | None = None

def execute_tool(name: str, arguments: dict, call_id: str,
                 executor: Callable) -> ToolResult:
    """Run a tool and return a typed ToolResult — never let the model skip this."""
    try:
        result = executor(name, arguments)
        return ToolResult(tool_name=name, call_id=call_id, content=str(result))
    except Exception as exc:
        # Return an error result so the model sees the failure explicitly
        return ToolResult(
            tool_name=name,
            call_id=call_id,
            content="",
            error=f"{type(exc).__name__}: {exc}",
        )

def safe_agent_loop(messages: list, model_call, tool_executor, max_steps=20):
    """
    Strict loop: tool calls are always executed and results always injected.
    The model never sees a missing result — Type 3 hallucination is impossible.
    """
    for _ in range(max_steps):
        response = model_call(messages)
        messages.append({"role": "assistant", "content": response.content})

        if not response.tool_calls:
            return response.content          # text reply — done

        for call in response.tool_calls:
            detector.validate_tool_call(call.name, call.arguments)  # Types 1 & 2
            result = execute_tool(
                call.name, call.arguments, call.id, tool_executor
            )
            # Always inject the result before the next model turn
            messages.append({
                "role": "tool",
                "tool_call_id": call.id,
                "content": result.error or result.content,
            })

    raise RuntimeError("max_steps exceeded — possible infinite loop")

import jsonschema, json

# Single source of truth — also used to generate the tool description
TOOLS: dict[str, dict] = {
    "create_ticket": {
        "description": "Create a support ticket.",
        "schema": {
            "type": "object",
            "properties": {
                "title":    {"type": "string", "minLength": 3},
                "priority": {"type": "string", "enum": ["HIGH","MEDIUM","LOW"]},
                "tags":     {"type": "array", "items": {"type": "string"}, "minItems": 1},
            },
            "required": ["title", "priority", "tags"],
            "additionalProperties": False,
        },
    },
}

def validate_against_runtime_schema(tool_name: str, arguments: dict) -> None:
    if tool_name not in TOOLS:
        raise ValueError(f"Unknown tool: {tool_name!r}")
    schema = TOOLS[tool_name]["schema"]
    try:
        jsonschema.validate(arguments, schema)
    except jsonschema.ValidationError as e:
        raise ValueError(f"Tool '{tool_name}' argument error: {e.message}")

# Hallucinated enum — caught
try:
    validate_against_runtime_schema("create_ticket", {
        "title": "Login broken",
        "priority": "CRITICAL",   # not in enum
        "tags": ["auth"],
    })
except ValueError as e:
    print(f"BLOCKED: {e}")
# BLOCKED: Tool 'create_ticket' argument error: 'CRITICAL' is not one of ['HIGH', 'MEDIUM', 'LOW']

import re
from dataclasses import dataclass, field

@dataclass
class HallucinationEvalResult:
    total_calls: int = 0
    hallucinated_tool: int = 0
    hallucinated_params: int = 0
    confabulated_results: int = 0
    rate: float = field(init=False)

    def __post_init__(self):
        self.rate = (
            (self.hallucinated_tool + self.hallucinated_params + self.confabulated_results)
            / max(self.total_calls, 1)
        )

def eval_agent_hallucinations(agent_fn, test_cases: list[dict]) -> HallucinationEvalResult:
    """
    Run agent on test_cases and measure hallucination rates.
    Each case: {"prompt": str, "expected_tool": str, "expected_args_subset": dict}
    """
    result = HallucinationEvalResult()

    for case in test_cases:
        response = agent_fn(case["prompt"])
        result.total_calls += 1

        if not hasattr(response, "tool_calls") or not response.tool_calls:
            continue

        call = response.tool_calls[0]

        if call.name not in TOOL_REGISTRY:
            result.hallucinated_tool += 1
            continue

        if call.name != case["expected_tool"]:
            result.hallucinated_tool += 1
            continue

        for k, v in case.get("expected_args_subset", {}).items():
            if call.arguments.get(k) != v:
                result.hallucinated_params += 1
                break

    return result

